const items = $input.all();
const agrupado = {};

// 1. Agrupando e limpando espaços invisíveis (Garante que o agrupamento não falhe)
for (const item of items) {
  const tipo = (item.json['Tipo de Usuário'] || 'Sem Tipo Definido').trim();
  if (!agrupado[tipo]) {
    agrupado[tipo] = [];
  }
  agrupado[tipo].push(item.json);
}

// 2. Construindo o HTML do E-mail (Sem tags interativas bloqueadas pelo Gmail)
let html = `
<div style="font-family: Arial, sans-serif; color: #333333; max-width: 800px; margin: 0 auto; border: 1px solid #e0e0e0; border-radius: 8px; overflow: hidden;">
  <div style="background-color: #005ce5; color: #ffffff; padding: 20px; text-align: center;">
      <h2 style="margin: 0;">Ação Necessária — Atendimentos Vinculados a CNPJs Baixados na Receita Federal</h2>
  </div>

  <div style="padding: 20px;">
    <p style="font-size: 16px;">Prezado(a),</p>

    <p style="line-height: 1.5;">Foram identificadas interações registradas vinculadas a CNPJs que constam como <strong>baixados na Receita Federal</strong>. Solicitamos a regularização conforme as instruções abaixo. O detalhamento completo encontra-se <strong>anexado nesta mensagem</strong>.</p>

    <div style="margin-top: 15px; margin-bottom: 25px; background-color: #f4f4f4; padding: 15px; border-left: 5px solid #005eb8;">
        <p style="line-height: 1.5; margin-top: 0; margin-bottom: 5px;"><strong>Orientações para regularização:</strong></p>
        <ul style="line-height: 1.5; margin-top: 0; margin-bottom: 0; padding-left: 20px;">
            <li style="margin-bottom: 5px;">Verificar se o atendimento foi realmente realizado na data registrada no sistema, ou seja, após a baixa do CNPJ.</li>
            <li style="margin-bottom: 5px;"><strong>Caso a data esteja incorreta:</strong> Deverá corrigir a data do atendimento no sistema.</li>
            <li style="margin-bottom: 5px;"><strong>Caso a data esteja correta:</strong> Verificar se o CNPJ registrado na interação corresponde de fato ao CNPJ atendido.</li>
            <li style="margin-bottom: 5px;"><strong>Permanência no FOCO:</strong> Caso os dados estejam corretos mas o CNPJ esteja baixado, o registro deverá ser editado para permanecer vinculado <strong>apenas à Pessoa Física</strong>, removendo a associação com o CNPJ.</li>
        </ul>
    </div>
`;

// 3. Montando as tabelas agrupadas visualmente (Já que o Dropdown é bloqueado)
for (const tipo in agrupado) {
  html += `
    <div style="margin-bottom: 20px; border: 1px solid #ccc; border-radius: 5px; overflow: hidden;">
      <div style="background-color: #e0e0e0; padding: 12px; font-weight: bold; color: #005ce5; font-size: 15px; border-bottom: 1px solid #ccc;">
        📂 ${tipo} (${agrupado[tipo].length} registros)
      </div>
      <div style="overflow-x: auto; background-color: #fff;">
        <table style="width: 100%; border-collapse: collapse; font-size: 13px;">
          <thead>
            <tr style="background-color: #f4f4f4; color: #333;">
              <th style="padding: 8px; border-bottom: 1px solid #ccc; text-align: left;">Atendente</th>
              <th style="padding: 8px; border-bottom: 1px solid #ccc; text-align: left;">Interação</th>
              <th style="padding: 8px; border-bottom: 1px solid #ccc; text-align: left;">CNPJ</th>
              <th style="padding: 8px; border-bottom: 1px solid #ccc; text-align: left;">Unidade</th>
            </tr>
          </thead>
          <tbody>
  `;
  for (const row of agrupado[tipo]) {
    html += `
            <tr>
              <td style="padding: 8px; border-bottom: 1px solid #eee;">${row['Atendente'] || '-'}</td>
              <td style="padding: 8px; border-bottom: 1px solid #eee;">${row['Interação Foco nº'] || '-'}</td>
              <td style="padding: 8px; border-bottom: 1px solid #eee;">${row['CNPJ'] || '-'}</td>
              <td style="padding: 8px; border-bottom: 1px solid #eee;">${row['Unidade Organizacional'] || '-'}</td>
            </tr>
    `;
  }
  html += `
          </tbody>
        </table>
      </div>
    </div>
  `;
}

html += `
    <p style="margin-top: 30px; font-size: 14px; color: #777;">
        Atenciosamente,<br>
        <strong>Núcleo de Atendimento e Desenvolvimento Regional</strong><br>
        Sebrae Goiás
    </p>
  </div>
</div>
`;

// 4. Arquivo Excel
let csvContent = '\uFEFFAtendente;CPF Atendente;Interação Foco nº;CNPJ;Situação Cadastral RFB;Unidade Organizacional;Tipo de Usuário\n';

for (const item of items) {
  const j = item.json;
  csvContent += `${j['Atendente'] || ''};${j['CPF Atendente'] || ''};${j['Interação Foco nº'] || ''};${j['CNPJ'] || ''};${j['Situação Cadastral RFB'] || ''};${j['Unidade Organizacional'] || ''};${j['Tipo de Usuário'] || ''}\n`;
}

const buffer = Buffer.from(csvContent, 'utf8');

return [{
  json: { 
    corpo_email: html 
  },
  binary: {
    planilha: {
      data: buffer.toString('base64'),
      mimeType: 'text/csv',
      fileName: 'Relatorio_CNPJs_Baixados.csv'
    }
  }
}];
